import{_ as a,c as e,o as r,a3 as l}from"./chunks/framework.DXA5WmbC.js";const o=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"misc/domain-spc.md","filePath":"misc/domain-spc.md","lastUpdated":1781674304000}');const t=a({name:"misc/domain-spc.md"},[["render",function(a,o,t,i,n,h){return r(),e("div",null,o[0]||(o[0]=[l('<h2 id="spc-controlchart-md" tabindex="-1">spc-controlchart.md <a class="header-anchor" href="#spc-controlchart-md" aria-label="Permalink to &quot;spc-controlchart.md&quot;">​</a></h2><h2 id="xbar-r-control-chart" tabindex="-1">Xbar-R Control Chart <a class="header-anchor" href="#xbar-r-control-chart" aria-label="Permalink to &quot;Xbar-R Control Chart&quot;">​</a></h2><ul><li>Xbar-R 관리도(평균치와 범위의 관리도)는 생산량이 많고 부분군의 개수가 3~4개, 공정평균과 변동을 함께 평가할 때</li><li>계량치 관리도의 대표</li><li>Xbar는 군의 평균치 변화, 군가의 변화를 확인</li><li>R은 군내의 산포 변화를 확인</li><li>공정을 분석하고 관리할 수있음</li><li>제품에 대해 품질을 보증할 수 있음</li></ul><h3 id="관리도-적용-목적" tabindex="-1">관리도 적용 목적 <a class="header-anchor" href="#관리도-적용-목적" aria-label="Permalink to &quot;관리도 적용 목적&quot;">​</a></h3><ul><li>공정의 품질에 대해 정확한 예측이 가능 ( 측정 오차 관리)</li><li>일정한 공정능력의 확보가 가능 (품질의 보증)</li><li>검사량 줄일 수 있음</li></ul><h3 id="xbar-관리도" tabindex="-1">Xbar 관리도 <a class="header-anchor" href="#xbar-관리도" aria-label="Permalink to &quot;Xbar 관리도&quot;">​</a></h3><ul><li>관리상한선(UCL): x + A2(관리도계수일람표)R</li><li>중앙선(CL)): x</li><li>관리하한선(LCL): x - A2(관리도계수일람표)R</li></ul><h3 id="r-관리도" tabindex="-1">R 관리도 <a class="header-anchor" href="#r-관리도" aria-label="Permalink to &quot;R 관리도&quot;">​</a></h3><ul><li>관리상한선(UCL): D4(관리도계수일람표)R</li><li>중앙선(CL)): R</li><li>관리하한선(LCL): D3(관리도계수일람표)R</li></ul><h3 id="관리도-확인-순서" tabindex="-1">관리도 확인 순서 <a class="header-anchor" href="#관리도-확인-순서" aria-label="Permalink to &quot;관리도 확인 순서&quot;">​</a></h3><ol><li>해석용 관리도를 그림</li><li>이상점을 제외하고 관리도 다시 그림</li><li>안정된 상태의 관계한계선을 구할 수 있음</li><li>관리용 관리도를 그림(관계한계선을 미리 그려넣음)</li><li>하루하루 측정한 데이터를 타점 후 공정의 이상상태를 빠르게 파악하고 개선할 수 있음</li></ol><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>엑셀활용하여 Xbar-R관리도 그리기: <a href="https://m.blog.naver.com/PostView.nhn?blogId=jiwoo6941&amp;logNo=220248024509&amp;proxyReferer=https:%2F%2Fwww.google.com%2F" target="_blank" rel="noreferrer">https://m.blog.naver.com/PostView.nhn?blogId=jiwoo6941&amp;logNo=220248024509&amp;proxyReferer=https:%2F%2Fwww.google.com%2F</a></li><li>관리도의 개념: <a href="http://contents.kocw.net/KOCW/document/2015/gachon/kimnamhyoung2/6.pdf" target="_blank" rel="noreferrer">http://contents.kocw.net/KOCW/document/2015/gachon/kimnamhyoung2/6.pdf</a></li><li>관리도의 개요 &amp; Xbar-R관리도 작성법: <a href="https://hujubkang.tistory.com/entry/%EA%B4%80%EB%A6%AC%EB%8F%84%EC%9D%98-%EA%B0%9C%EC%9A%94" target="_blank" rel="noreferrer">https://hujubkang.tistory.com/entry/관리도의-개요</a></li></ul><h2 id="spc-processcapability-md" tabindex="-1">spc-processcapability.md <a class="header-anchor" href="#spc-processcapability-md" aria-label="Permalink to &quot;spc-processcapability.md&quot;">​</a></h2><h2 id="통계적-공정능력도에" tabindex="-1">통계적 공정능력도에 <a class="header-anchor" href="#통계적-공정능력도에" aria-label="Permalink to &quot;통계적 공정능력도에&quot;">​</a></h2><ol><li>막대 그래프, 꺾은선그래프, 원그래프 -&gt; 경영 관리, 생산 관리, 품질 관리 등 업무에 적용</li><li>체크시트 -&gt; 설비/장비 점검, 측정기 등의 업무에 적용</li><li>X-R 관리도 -&gt; 수입 검사, 공정 검사, 최종 검사 등 업무에 적용</li><li>공정 능력 -&gt; 수입 검사, 공정 검사, 최종 검사 등 업무에 적용</li></ol><p>관리도</p><h2 id="references-1" tabindex="-1">References <a class="header-anchor" href="#references-1" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://slidesplayer.org/slide/15042981/" target="_blank" rel="noreferrer">https://slidesplayer.org/slide/15042981/</a></li><li><a href="https://m.blog.naver.com/PostView.nhn?blogId=kqm45&amp;logNo=220975745063&amp;proxyReferer=https:%2F%2Fwww.google.com%2F" target="_blank" rel="noreferrer">https://m.blog.naver.com/PostView.nhn?blogId=kqm45&amp;logNo=220975745063&amp;proxyReferer=https:%2F%2Fwww.google.com%2F</a></li></ul>',19)]))}]]);export{o as __pageData,t as default};
